import{_ as e,o as a,c as o,a0 as i}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Alliance Mobilization","description":"","frontmatter":{},"headers":[],"relativePath":"events/alliance-mobilization.md","filePath":"events/alliance-mobilization.md"}'),l={name:"events/alliance-mobilization.md"};function n(s,t,r,h,d,c){return a(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="alliance-mobilization" tabindex="-1">Alliance Mobilization <a class="header-anchor" href="#alliance-mobilization" aria-label="Permalink to &quot;Alliance Mobilization&quot;">​</a></h1><p>Alliance Mobilization is the default template for the multi-day mission event where scores build toward one running total across the event window.</p><h2 id="how-this-default-is-set-up" tabindex="-1">How this default is set up <a class="header-anchor" href="#how-this-default-is-set-up" aria-label="Permalink to &quot;How this default is set up&quot;">​</a></h2><ul><li>event style: multi-day</li><li>score entry: cumulative total</li><li>score label: <strong>Points</strong></li><li>default duration: 7 days</li><li>participation tracked: yes</li></ul><p>This is the main default where <strong>later imports update the running total</strong> instead of behaving like separate one-off scores.</p><h2 id="what-cumulative-scoring-means" tabindex="-1">What cumulative scoring means <a class="header-anchor" href="#what-cumulative-scoring-means" aria-label="Permalink to &quot;What cumulative scoring means&quot;">​</a></h2><p>In this event, the score for a player is treated as their latest known total for that date.</p><p>Example:</p><ol><li>On Day 2, you import a row showing <code>Player A = 12,000</code>.</li><li>On Day 4, you import a row showing <code>Player A = 19,500</code>.</li></ol><p>The tracker does not add those together as <code>31,500</code>.</p><p>Instead, it understands that:</p><ul><li><code>12,000</code> was the running total on Day 2</li><li><code>19,500</code> was the running total on Day 4</li></ul><p>So the latest total becomes <code>19,500</code>, and analytics can derive the gain between days.</p><h2 id="what-to-import" tabindex="-1">What to import <a class="header-anchor" href="#what-to-import" aria-label="Permalink to &quot;What to import&quot;">​</a></h2><p>Upload the personal points ranking for the correct date inside the event window.</p><p>The date matters here more than it does in single-session events, because each dated import updates that day&#39;s cumulative snapshot.</p><h2 id="what-to-watch-out-for" tabindex="-1">What to watch out for <a class="header-anchor" href="#what-to-watch-out-for" aria-label="Permalink to &quot;What to watch out for&quot;">​</a></h2><ul><li>do not treat repeated imports as separate stage scores</li><li>make sure the event date matches the day shown in the screenshot</li><li>if you re-import the same date, you are updating that day&#39;s snapshot rather than creating a second total</li></ul><h2 id="why-this-matters-for-analytics" tabindex="-1">Why this matters for analytics <a class="header-anchor" href="#why-this-matters-for-analytics" aria-label="Permalink to &quot;Why this matters for analytics&quot;">​</a></h2><p>Because the tracker stores dated totals, it can show:</p><ul><li>latest known total</li><li>day-to-day gains</li><li>missing dates in the event window</li></ul><h2 id="protection-note" tabindex="-1">Protection note <a class="header-anchor" href="#protection-note" aria-label="Permalink to &quot;Protection note&quot;">​</a></h2><p>This is a default template, so it is <strong>editable but not deletable</strong>. See <a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./default-events.html">The Default Events</a></li><li><a href="./../how-to/create-instance.html">Create an Event Instance</a></li><li><a href="./../how-to/instance-detail.html">Work Inside an Instance</a></li><li><a href="./../imports/upload-screenshots.html">Upload Screenshots</a></li></ul>',25)])])}const m=e(l,[["render",n]]);export{p as __pageData,m as default};
